object Solution {
  /**
    * Calculates the sum of absolute differences between the frequencies of characters and their mirror characters
    * for all unique mirror pairs in the string s.
    *
    * @param s The input string consisting of lowercase English letters and digits.
    * @return The total sum of absolute differences.
    */
  def s(s: String): Long = {
    // 1. Calculate frequencies of all characters
    val freqMap = mutable.Map[Char, Int]()
    for (c <- s) {
      freqMap(c) = freqMap.getOrElse(c, 0) + 1
    }

    // Helper function to get the mirror character
    def getMirror(c: Char): Char = {
      if (c.isLetter()) {
        // For letters: 'a' <-> 'z', 'b' <-> 'y', etc.
        // 'a' is 0, 'z' is 25. Mirror index = 25 - (c - 'a')
        val offset = c - 'a'
        val mirrorOffset = 25 - offset
        ('a' + mirrorOffset).toChar
      } else if (c.isDigit()) {
        // For digits: '0' <-> '9', '1' <-> '8', etc.
        // '0' is 0, '9' is 9. Mirror digit = 9 - (digit - 0)
        val digitValue = c.toString.toInt
        val mirrorValue = 9 - digitValue
        mirrorValue.toString[Char]
      } else {
        c // Should not happen based on problem description
      }
    }

    var totalSum: Long = 0

    // Set to keep track of pairs already processed to avoid double counting
    // We store the canonical representation of the pair (min_char, max_char)
    val processedPairs = mutable.Set[Char]().toSet

    // Iterate over all unique characters present in the string
    for (c <- freqMap.keys) {
      if (processedPairs.contains(c)) {
        continue
      }

      val m = getMirror(c)

      // Ensure we only process the pair once.
      // We process (c, m) only if c <= m (lexicographically or numerically consistent)
      // Or, more simply, only proceed if c is the canonical representative of the pair.
      // A robust way is to use a canonical ordering: always pick the lexicographically smaller one,
      // UNLESS c == m (self-mirroring, e.g., 'm'/'n' is not self-mirroring, 'x' is self-mirroring).

      // If c == m, it's a self-mirroring character. Process it directly.
      if (c == m) {
        val freqC = freqMap(c)
        val freqM = freqMap.getOrElse(m, 0)
        totalSum += Math.abs(freqC - freqM).toLong
        processedPairs.add(c)
        continue
      }

      // If c != m, we ensure we only calculate for the pair once.
      // We check if 'c' is the "smaller" character in the pair {c, m}.
      if (c < m) {
        val freqC = freqMap.getOrElse(c, 0)
        val freqM = freqMap.getOrElse(m, 0)

        val diff = Math.abs(freqC - freqM).toLong
        totalSum += diff

        // Mark both characters as processed so we don't process (m, c) later
        processedPairs.add(c)
        processedPairs.add(m)
      }
      // If c > m, the pair (m, c) would have already been processed when the loop reached m.
    }

    totalSum
  }
}
